import anthropic

client = anthropic.Anthropic()

# Difficulty -> thinking budget. The cheap classifier picks the key.
BUDGETS = {
    "easy":   1024,
    "medium": 4096,
    "hard":  16384,
}


def classify_difficulty(question: str) -> str:
    # Stand-in for a cheap learned router or heuristic.
    # Real implementations: small-model judge, length + operator
    # features, or prior-task similarity.
    if len(question) < 80:
        return "easy"
    if any(k in question.lower() for k in ["prove", "derive", "optimize"]):
        return "hard"
    return "medium"


def answer(question: str):
    budget = BUDGETS[classify_difficulty(question)]

    return client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=budget + 4096,            # answer headroom on top of thinking
        thinking={
            "type": "enabled",
            "budget_tokens": budget,         # per-query compute allocation
        },
        messages=[{"role": "user", "content": question}],
    )


print(answer("What is 2+2?"))
print(answer("Prove that the halting problem is undecidable."))

import dspy

dspy.configure(lm=dspy.LM("openai/gpt-4o-mini"))


class AdaptiveAnswer(dspy.Module):
    def __init__(self):
        super().__init__()
        # Cheap path: no rationale, one shot.
        self.fast = dspy.Predict("question -> answer")
        # Expensive path: ChainOfThought spends an extra rationale.
        self.deep = dspy.ChainOfThought("question -> answer")

    def forward(self, question: str):
        # Cheap heuristic stands in for a learned difficulty classifier.
        hard = (
            len(question) > 80
            or any(k in question.lower()
                   for k in ["prove", "derive", "optimize"])
        )
        if hard:
            return self.deep(question=question)
        return self.fast(question=question)


solve = AdaptiveAnswer()
print(solve(question="What is 2+2?").answer)
print(solve(question="Prove that there are infinitely many primes.").answer)

function answer_with_cot(question):
    system = "Solve the problem. First write your reasoning,
              then on a new line write 'Answer:' followed by
              the final answer."
    reply = llm.generate(
        system=system,
        user=question,
    )

    # Parse the trace so callers can audit reasoning separately.
    if "Answer:" in reply:
        reasoning, answer = reply.rsplit("Answer:", 1)
    else:
        reasoning, answer = reply, ""

    return {
        "reasoning": reasoning.strip(),
        "answer": answer.strip(),
    }

function answer_with_extended_thinking(question, difficulty):
    # Per-task budget: cheap for routing, expensive for hard reasoning.
    budget = {
        "routing": 1024,
        "normal":  4096,
        "hard":   16384,
    }[difficulty]

    response = llm.generate(
        model="reasoning-capable-model",
        messages=[user(question)],
        thinking={
            "type": "enabled",
            "budget_tokens": budget,    # API name varies by provider
        },
    )

    # Most providers return reasoning separately from the answer.
    log_usage({
        "reasoning_tokens": response.usage.reasoning_tokens,
        "output_tokens":    response.usage.output_tokens,
    })
    return response.content

