class Thought:
    id, content, score, parents = ...

class GraphOfThoughts:
    def __init__(self, problem):
        self.nodes = {}
        self.root = self.add(content=problem, parents=[])

    def add(self, content, parents):
        t = Thought(id=new_id(), content=content,
                    score=None, parents=parents)
        self.nodes[t.id] = t
        return t

    def generate(self, node, k):
        # CoT-style expansion: produce k child thoughts.
        for c in llm.sample(node.content, n=k):
            self.add(content=c, parents=[node])

    def refine(self, node):
        improved = llm.improve(node.content)
        return self.add(content=improved, parents=[node])

    def aggregate(self, nodes):
        merged = llm.merge([n.content for n in nodes])
        return self.add(content=merged, parents=nodes)

    def score(self, node):
        node.score = llm.score(node.content)

# Orchestrator chains operations to produce the final thought.
g = GraphOfThoughts(problem)
g.generate(g.root, k=5)
candidates = list(g.nodes.values())[1:]
for n in candidates:
    g.score(n)
top = sorted(candidates, key=lambda n: -n.score)[:3]
final = g.aggregate(top)
return final.content

# Production GoT with bounded node count, score-gated early exit,
# operator trace, and escalation if the graph saturates without a
# winner that clears the confidence floor.

NODE_CAP         = 30
SCORE_FLOOR      = 0.82
MAX_DEPTH        = 4

class BoundedGraph:
    def __init__(self, problem):
        self.nodes = {}
        self.ops   = []           # operator trace
        self.root  = self._add(problem, parents=[])

    def _add(self, content, parents):
        if len(self.nodes) >= NODE_CAP:
            raise BudgetExhausted("node_cap")
        t = {"id": new_id(), "content": content, "score": None,
             "parents": [p["id"] for p in parents]}
        self.nodes[t["id"]] = t
        return t

    def generate(self, node, k):
        for c in llm.sample(node["content"], n=k):
            n = self._add(c, parents=[node])
            self.ops.append({"op": "generate", "from": node["id"],
                              "to": n["id"]})

    def refine(self, node):
        improved = llm.improve(node["content"])
        n = self._add(improved, parents=[node])
        self.ops.append({"op": "refine", "from": node["id"], "to": n["id"]})
        return n

    def aggregate(self, nodes):
        merged = llm.merge([n["content"] for n in nodes])
        n = self._add(merged, parents=nodes)
        self.ops.append({"op": "aggregate",
                          "from": [x["id"] for x in nodes],
                          "to": n["id"]})
        return n

    def score(self, node):
        node["score"] = llm.score(node["content"])

def solve(problem):
    g = BoundedGraph(problem)
    try:
        for depth in range(MAX_DEPTH):
            frontier = [n for n in g.nodes.values() if n["score"] is None]
            for f in frontier[:5]:
                g.generate(f, k=3)
            for n in g.nodes.values():
                if n["score"] is None:
                    g.score(n)
            top = sorted(g.nodes.values(), key=lambda n: -(n["score"] or 0))[:3]
            if top[0]["score"] >= SCORE_FLOOR:
                return {"answer": top[0]["content"],
                        "trace": g.ops, "path": "early_exit"}
            g.aggregate(top)
    except BudgetExhausted as e:
        pass

    best = max(g.nodes.values(), key=lambda n: n["score"] or 0)
    if (best["score"] or 0) < SCORE_FLOOR:
        return escalate(problem, reason="graph_saturated", evidence=g.ops)
    return {"answer": best["content"], "trace": g.ops, "path": "saturated"}

# Why this works: the node cap stops the DAG from exploding, the score
# floor turns 'best so far' into a real bar, and the operator trace
# makes the merged answer reconstructible from generate/refine/aggregate.
# Related: see `tree-of-thoughts`, `lats`, `llm-compiler`.

# Compose LRM routing with extended-thinking: when the router picks the
# LRM, it also picks a thinking-token budget keyed to task complexity,
# so 'pick the model' and 'pick how long it thinks' are one decision.

THINKING_BUDGETS = {
    "low":     2_000,
    "medium": 10_000,
    "high":   40_000,
}

def classify_with_budget(task):
    if task.kind == "theorem":
        return "lrm", "high"
    if task.kind == "math_multi_step":
        return "lrm", "medium"
    if task.kind == "constraint_sat":
        return "lrm", "high" if task.n_constraints > 10 else "medium"
    if regex_search(r"(prove|derive|optimi[sz]e)", task.text):
        return "lrm", "medium"
    return "llm", None

def answer(task):
    route, level = classify_with_budget(task)

    if route == "llm":
        return {"answer": llm_client("fast-llm").generate(task),
                "route": "llm"}

    budget_tokens = THINKING_BUDGETS[level]
    result = llm_client("reasoning-lrm").generate(
        task,
        thinking={"budget_tokens": budget_tokens, "type": "enabled"},
    )

    metrics.observe("lrm.thinking_used", result.thinking_tokens,
                     tags={"level": level, "kind": task.kind})

    # If the LRM hit its budget without converging, escalate the level.
    if result.stopped_on == "thinking_budget" and level != "high":
        next_level = "high"
        result = llm_client("reasoning-lrm").generate(
            task,
            thinking={"budget_tokens": THINKING_BUDGETS[next_level],
                       "type": "enabled"},
        )
        level = next_level

    return {"answer": result.text, "route": "lrm", "level": level,
            "thinking_tokens": result.thinking_tokens}

# Why this works: routing to the LRM is necessary but not sufficient;
# a one-shot LRM call with a tiny thinking budget under-uses it, and a
# huge budget overpays on easy tasks. Coupling the budget to complexity
# (and bumping up on budget-exhausted) keeps spend proportional.
# Related: see `extended-thinking`, `test-time-compute-scaling`, `multi-model-routing`.

# Production least-to-most: bound subproblem count, retry parse failures,
# early-exit if an intermediate already answers the question, escalate on
# detected contradictions between steps, and trace every step.

MAX_SUBPROBLEMS  = 8
MAX_RETRIES      = 2
CONFIDENCE_FLOOR = 0.80

def least_to_most(question, budget):
    trace = {"decomposition": None, "steps": []}

    decompose_prompt = (
        f"Break this problem into up to {MAX_SUBPROBLEMS} numbered "
        "subproblems from easiest to hardest. Each subproblem must be "
        "answerable from the original question plus earlier answers.\n"
        f"QUESTION: {question}"
    )
    subproblems = parse_numbered(llm.generate(user=decompose_prompt))
    subproblems = subproblems[:MAX_SUBPROBLEMS]
    trace["decomposition"] = subproblems

    solved = []
    for i, sub in enumerate(subproblems):
        prior = "\n".join(f"Q{j+1}: {q}\nA{j+1}: {a['answer']}"
                          for j, (q, a) in enumerate(solved))
        attempt = None
        for r in range(MAX_RETRIES + 1):
            raw = llm.generate(user=(
                f"ORIGINAL: {question}\nPRIOR:\n{prior}\n"
                f"CURRENT: {sub}\nAnswer concisely. End with: "
                f"CONFIDENCE=<0-1>"
            ))
            parsed = parse_answer_with_confidence(raw)
            if parsed is not None:
                attempt = parsed; break
        if attempt is None:
            return escalate(question, reason="parse_failure",
                             evidence=trace, step=i)

        # Contradiction check against prior answers.
        if contradicts_any(attempt, [a for _, a in solved]):
            return escalate(question, reason="step_contradicts_prior",
                             evidence={**trace, "contradict_at": i})
        solved.append((sub, attempt))
        trace["steps"].append({"q": sub, **attempt})

        # Early exit: an intermediate already answers the original.
        if (attempt["confidence"] >= CONFIDENCE_FLOOR
            and answers_original(attempt["answer"], question)):
            return {"answer": attempt["answer"], "trace": trace,
                    "path": "early_exit", "step": i}

    return {"answer": solved[-1][1]["answer"], "trace": trace,
            "path": "completed"}

# Why this works: caps stop runaway decompositions, retries handle parse
# slop without aborting, contradiction detection catches drift between
# steps, and the trace makes the chain auditable end-to-end.
# Related: see `chain-of-thought`, `plan-and-execute`, `goal-decomposition`.

function rest_em(base_model, problems, ground_truth, R, K):
    model = base_model
    for round in 1..R:
        # E-step: generate K responses per problem with the current model.
        accepted = []
        for p in problems:
            for k in 1..K:
                resp = sample(model, p, temperature=0.8)
                # Reward can be exact-match against ground_truth
                # OR an executable test (unit test, code runner).
                if reward(resp, ground_truth[p]) >= THRESHOLD:
                    accepted.append({"prompt": p, "completion": resp})

        if not accepted:
            break   # collapse: model produces nothing reward-able

        # M-step: supervised fine-tune the BASE model on accepted set.
        # (ReST-EM restarts from base each round to avoid drift.)
        model = supervised_finetune(
            base_model=base_model,
            data=accepted,
        )

    return model

SELF_ASK_PROMPT = """Question: {q}
Are follow up questions needed here: Yes.
Follow up:"""

function self_ask(question, search_tool):
    transcript = SELF_ASK_PROMPT.format(q=question)

    for step in 1..MAX_STEPS:
        # Model emits the next follow-up question (or final answer).
        chunk = llm.generate(
            prompt=transcript,
            stop=["Intermediate answer:", "So the final answer is"],
        )
        transcript += chunk

        if "So the final answer is" in chunk:
            return chunk.split("So the final answer is")[-1].strip()

        # Otherwise the chunk ends with a follow-up question.
        followup = chunk.strip().splitlines()[-1]
        intermediate = search_tool(followup)
        transcript += f"\nIntermediate answer: {intermediate}\nFollow up:"

    return abort("step budget exhausted")

# Production self-ask: step budget, per-followup tool routing, confidence
# extraction on the final answer, transcript audit, and escalation when
# follow-ups keep looping on the same sub-question.

MAX_STEPS        = 8
CONFIDENCE_FLOOR = 0.75

TOOLS = {
    "search":     web_search_tool,
    "calculator": calculator_tool,
    "lookup":     local_kb_lookup,
}

def route_followup(q):
    if regex_search(r"^\s*(compute|calculate|what is \d)", q):
        return "calculator"
    if regex_search(r"(who|when|where|how many|which)", q):
        return "search"
    return "lookup"

SELF_ASK_PROMPT = (
    "Question: {q}\n"
    "Are follow up questions needed: Yes.\nFollow up:"
)

def self_ask(question):
    transcript = SELF_ASK_PROMPT.format(q=question)
    seen_followups = set()
    audit = []

    for step in range(MAX_STEPS):
        chunk = llm.generate(
            prompt=transcript,
            stop=["Intermediate answer:", "So the final answer is"],
        )
        transcript += chunk

        if "So the final answer is" in chunk:
            ans = chunk.split("So the final answer is")[-1].strip()
            conf = llm.score_confidence(question, ans, transcript)
            audit.append({"step": step, "final": ans, "conf": conf})
            if conf >= CONFIDENCE_FLOOR:
                return {"answer": ans, "transcript": transcript,
                        "audit": audit, "path": "committed"}
            return escalate(question, reason="low_confidence_final",
                             evidence={"audit": audit})

        followup = chunk.strip().splitlines()[-1]
        if followup in seen_followups:
            return escalate(question, reason="followup_loop",
                             evidence={"repeat": followup, "audit": audit})
        seen_followups.add(followup)

        tool_name = route_followup(followup)
        result    = TOOLS[tool_name](followup)
        audit.append({"step": step, "followup": followup,
                       "tool": tool_name, "result": result})
        transcript += (f"\nIntermediate answer: {result}"
                        f"\nFollow up:")

    return escalate(question, reason="step_budget", evidence={"audit": audit})

# Why this works: tool-routing each follow-up lets calculators answer math
# and search answer facts; the confidence floor and the loop detector
# stop the model from rubber-stamping a weak final answer or spinning on
# the same sub-question forever.
# Related: see `react`, `least-to-most`, `query-decomposition-agent`.

function star(base_model, dataset, R):
    model = base_model
    for round in 1..R:
        kept = []

        for (question, gold_answer) in dataset:
            # 1. Generate a rationale + answer with CoT prompting.
            rationale, answer = cot_generate(model, question)

            if answer == gold_answer:
                # Correct: keep the rationale as a training example.
                kept.append({
                    "prompt":     question,
                    "completion": rationale + "\nAnswer: " + answer,
                })
            else:
                # 2. Rationalization: give the gold answer as a hint
                #    and ask the model to produce a rationale that
                #    *would have* justified it.
                hinted = cot_generate_with_hint(
                    model, question, hint=gold_answer,
                )
                kept.append({
                    "prompt":     question,
                    "completion": hinted + "\nAnswer: " + gold_answer,
                })

        # 3. Fine-tune on the kept (correct + rationalized) set.
        model = supervised_finetune(base_model, data=kept)

    return model

function answer_with_scaled_compute(task, budget):
    cls = classify(task)

    if cls == "verifier_amenable":
        # Best-of-N: sample N answers, pick the highest-scoring.
        cands = [llm.sample(task) for _ in range(budget.N)]
        return argmax(cands, key=verifier.score)

    if cls == "sampling_amenable":
        # Self-consistency: sample, then majority-vote the answer.
        cands = [llm.sample(task, temperature=0.7)
                 for _ in range(budget.N)]
        return majority_vote([extract_answer(c) for c in cands])

    if cls == "combinatorial":
        # Tree search over thought steps (see tree-of-thoughts).
        return tree_search(task, width=budget.W, depth=budget.D)

    if cls == "sequential_reasoning":
        # Extended thinking: longer internal CoT budget.
        return llm.generate(
            task, thinking={"budget_tokens": budget.thinking},
        )

    return llm.generate(task)   # default: single pass

# Production scaled-compute: a budget allocator picks technique AND budget
# per task, with an early-exit confidence floor and a hard escalation when
# even the max budget fails to clear it. Per-class spend is tracked.

CONFIDENCE_FLOOR = 0.85

ALLOCATIONS = {
    "verifier_amenable":    {"tech": "best_of_n",    "N": 16},
    "sampling_amenable":    {"tech": "self_consist",  "N": 32},
    "combinatorial":        {"tech": "tree_search",   "W": 5, "D": 4},
    "sequential_reasoning": {"tech": "extended_think", "thinking": 20_000},
    "trivial":              {"tech": "single_pass"},
}

def answer_with_scaled_compute(task, budget):
    cls   = classify(task)
    alloc = ALLOCATIONS[cls]
    metrics.inc("ttc.dispatch", tags={"class": cls})

    if alloc["tech"] == "single_pass":
        ans = llm.generate(task)
        return {"answer": ans, "class": cls, "path": "single"}

    if alloc["tech"] == "best_of_n":
        cands = []
        for i in range(min(alloc["N"], budget.samples)):
            c = llm.sample(task)
            s = verifier.score(c)
            cands.append((c, s))
            if s >= CONFIDENCE_FLOOR:
                metrics.inc("ttc.early_exit", tags={"class": cls})
                return {"answer": c, "score": s, "path": "early_exit"}
        best = max(cands, key=lambda x: x[1])
        if best[1] < CONFIDENCE_FLOOR:
            return escalate(task, reason="bon_below_floor", best=best)
        return {"answer": best[0], "score": best[1], "path": "bon_best"}

    if alloc["tech"] == "self_consist":
        cands = [llm.sample(task, temperature=0.7)
                 for _ in range(alloc["N"])]
        ans, margin = majority_vote_with_margin(
            [extract_answer(c) for c in cands]
        )
        if margin < 0.40:
            return escalate(task, reason="low_vote_margin", margin=margin)
        return {"answer": ans, "margin": margin, "path": "sc"}

    if alloc["tech"] == "tree_search":
        return tree_search(task, width=alloc["W"], depth=alloc["D"])

    if alloc["tech"] == "extended_think":
        r = llm.generate(task,
                          thinking={"budget_tokens": alloc["thinking"]})
        if r.stopped_on == "thinking_budget":
            return escalate(task, reason="thinking_budget_exhausted")
        return {"answer": r.text, "path": "extended_think"}

# Why this works: the allocator turns 'pick a technique' into 'pick a
# technique AND a budget'; early exit on the verifier score saves the
# rest of the budget; escalation makes silent under-compute visible.
# Related: see `best-of-n`, `self-consistency`, `tree-of-thoughts`.

function tree_of_thoughts(problem, B=3, K=5, MAX_DEPTH=4):
    root = {"path": [], "state": problem}
    frontier = [root]

    for depth in 1..MAX_DEPTH:
        # 1. Expand: each node proposes K next thoughts.
        children = []
        for node in frontier:
            for thought in llm.sample_thoughts(node, k=K):
                children.append({
                    "path":  node["path"] + [thought],
                    "state": apply(node["state"], thought),
                })

        # 2. Evaluate: self-evaluate each child (or use a programmatic
        #    checker for math / code).
        for c in children:
            c["score"] = llm.evaluate(c["state"])  # e.g. "sure/maybe/no"

        # 3. Prune: keep the top-B by score. Backtracking is implicit
        #    here: low-scoring branches simply drop off the frontier.
        frontier = sorted(children, key=lambda c: -c["score"])[:B]

        if any(is_terminal(c["state"]) for c in frontier):
            break

    best = max(frontier, key=lambda c: c["score"])
    return best["path"], best["state"]

# Production ToT: node cap, score-gated early exit, structured trace of
# expansions and prunings, and escalation when the search saturates
# without reaching a leaf above the confidence floor.

NODE_CAP         = 80
SCORE_FLOOR      = 0.85
MAX_DEPTH        = 5
BEAM             = 3
SAMPLES_PER_NODE = 4

def tree_of_thoughts(problem, budget):
    nodes_seen = 0
    trace      = {"expansions": [], "prunings": []}

    root     = {"path": [], "state": problem, "score": None}
    frontier = [root]

    for depth in range(MAX_DEPTH):
        if nodes_seen >= NODE_CAP:
            break

        children = []
        for node in frontier:
            for thought in llm.sample_thoughts(node, k=SAMPLES_PER_NODE):
                c = {"path":  node["path"] + [thought],
                     "state": apply(node["state"], thought),
                     "depth": depth + 1, "score": None}
                children.append(c)
                nodes_seen += 1
                trace["expansions"].append({"depth": depth, "thought": thought})
                if nodes_seen >= NODE_CAP:
                    break
            if nodes_seen >= NODE_CAP:
                break

        for c in children:
            c["score"] = llm.evaluate(c["state"])
            # Early exit: terminal child clears the floor.
            if is_terminal(c["state"]) and c["score"] >= SCORE_FLOOR:
                return {"answer": c["state"], "path": c["path"],
                        "trace": trace, "exit": "early_terminal"}

        kept   = sorted(children, key=lambda c: -c["score"])[:BEAM]
        pruned = [c for c in children if c not in kept]
        trace["prunings"].extend(
            {"depth": depth, "path": p["path"], "score": p["score"]}
            for p in pruned
        )
        frontier = kept

        if any(is_terminal(c["state"]) for c in frontier):
            break

    best = max(frontier, key=lambda c: c["score"] or 0)
    if (best["score"] or 0) < SCORE_FLOOR:
        return escalate(problem, reason="tree_saturated",
                         evidence={"best": best, "trace": trace})
    return {"answer": best["state"], "path": best["path"],
            "trace": trace, "exit": "best_leaf"}

# Why this works: a node cap protects budget, the per-child score floor
# enables early exit on a confident leaf, and the pruning trace makes
# 'why didn't we explore that branch' answerable after the fact.
# Related: see `chain-of-thought`, `lats`, `graph-of-thoughts`.

# Compose ToT with world-model-as-tool: each candidate node's score comes
# from running its partial state through a deterministic simulator, not
# from LLM self-evaluation. Hard failures prune immediately.

WORLD_MODEL = world_model_tool   # deterministic simulator

def tot_with_world_model(problem, B=3, K=5, MAX_DEPTH=4):
    root     = {"path": [], "state": problem, "score": None,
                "sim": None}
    frontier = [root]

    for depth in range(MAX_DEPTH):
        children = []
        for node in frontier:
            for thought in llm.sample_thoughts(node, k=K):
                child_state = apply(node["state"], thought)

                # Delegate evaluation to the world model.
                sim = WORLD_MODEL.simulate(child_state)

                if sim.invariant_violated:
                    # Hard prune: the simulator says this branch is
                    # impossible (e.g. constraint violation, illegal move).
                    metrics.inc("tot.world_model.hard_prune")
                    continue

                children.append({
                    "path":  node["path"] + [thought],
                    "state": child_state,
                    "sim":   sim,
                    "score": sim.objective_value,    # numeric, not LLM
                })

        if not children:
            return escalate(problem, reason="all_children_pruned")

        frontier = sorted(children, key=lambda c: -c["score"])[:B]

        # Terminal goal-test is also the simulator's call.
        for c in frontier:
            if WORLD_MODEL.is_goal(c["state"]):
                return {"answer": c["state"], "path": c["path"],
                        "exit": "world_model_goal"}

    best = max(frontier, key=lambda c: c["score"])
    return {"answer": best["state"], "path": best["path"],
            "exit": "best_leaf", "sim": best["sim"]}

# Why this works: LLM self-evaluation can rationalise any branch as
# 'sure'; a deterministic world-model gives hard invariants the LLM
# cannot talk its way past, so the tree prunes truly-illegal branches
# and ranks the rest on real objective values.
# Related: see `world-model-as-tool`, `lats`, `chain-of-thought`.

# Compose zero-shot CoT with chain-of-thought: default to the cheap
# zero-shot trigger; only fall back to few-shot CoT (with curated
# exemplars for this task family) when the zero-shot pass underperforms.

ZS_TRIGGER  = "Let's think step by step."
FS_EXEMPLARS_BY_FAMILY = {
    "arithmetic": [...],   # 4-6 worked examples
    "date_qa":    [...],
    "symbolic":   [...],
}
CONFIDENCE_FLOOR = 0.75

def zs_with_cot_fallback(question, task_family):
    # 1. Cheap zero-shot pass.
    reasoning = llm.generate(
        prompt=f"Q: {question}\nA: {ZS_TRIGGER}",
    )
    answer = llm.generate(
        prompt=(
            f"Q: {question}\nA: {ZS_TRIGGER} {reasoning}\n"
            f"Therefore, the answer is"
        ),
        max_tokens=24,
    )
    conf = llm.score_confidence(question, answer, reasoning)

    if conf >= CONFIDENCE_FLOOR:
        metrics.inc("zs.kept", tags={"family": task_family})
        return {"answer": answer, "path": "zero_shot",
                "reasoning": reasoning}

    # 2. Few-shot fallback with curated exemplars for this family.
    exemplars = FS_EXEMPLARS_BY_FAMILY.get(task_family, [])
    if not exemplars:
        # No exemplars available — return the zero-shot answer with a flag.
        return {"answer": answer, "path": "zero_shot_low_conf",
                "warning": f"no_exemplars_for_{task_family}"}

    few_shot_prompt = format_exemplars(exemplars) + (
        f"\n\nQ: {question}\nA: Let's think step by step."
    )
    fs_reasoning = llm.generate(prompt=few_shot_prompt)
    fs_answer    = llm.generate(
        prompt=few_shot_prompt + fs_reasoning + "\nTherefore, the answer is",
        max_tokens=24,
    )
    metrics.inc("zs.fallback_to_fs", tags={"family": task_family})

    return {"answer": fs_answer, "path": "few_shot_fallback",
            "zero_shot_attempt": answer, "reasoning": fs_reasoning}

# Why this works: few-shot CoT carries the cost of curated exemplars
# for every task family; running zero-shot first and only paying that
# cost on low-confidence cases captures the easy majority cheaply while
# keeping the harder cases on the more reliable few-shot path.
# Related: see `chain-of-thought`, `self-consistency`.
